+fn matrix_transpose(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
+    // Passthrough to np.linalg.matrix_transpose. Transposes the last
+    // two axes of x; preserves all leading batch dimensions and dtype.
